namespace CSharpLINQCollections
{
    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public decimal Price { get; set; }
        public int Stock { get; set; }
    }

    class Program
    {
        static void Main()
        {
            var numbers = new List<int> { 5, 3, 8, 1, 9, 2 };
            numbers.Sort();
            Console.WriteLine(string.Join(", ", numbers));

            var prices = new Dictionary<string, decimal>
            {
                ["Táo"] = 15000,
                ["Cam"] = 20000
            };
            Console.WriteLine($"Giá Cam: {prices["Cam"]:C}");

            var evens = numbers.Where(n => n % 2 == 0);
            Console.WriteLine($"Số chẵn: {string.Join(", ", evens)}");

            var sorted = numbers.OrderByDescending(n => n);
            Console.WriteLine($"Giảm dần: {string.Join(", ", sorted.Take(3))}");

            var products = new List<Product>
            {
                new() { Id = 1, Name = "Laptop", Price = 20000000, Stock = 10 },
                new() { Id = 2, Name = "Chuột", Price = 200000, Stock = 50 }
            };

            var byCategory = products.GroupBy(p => p.Name);
            foreach (var group in byCategory)
                Console.WriteLine($"{group.Key}: {group.Count()} sản phẩm");

            bool hasExpensive = products.Any(p => p.Price > 10000000);
            Console.WriteLine($"Có sản phẩm >10M? {hasExpensive}");

            foreach (var fib in Fibonacci(10))
                Console.Write($" {fib}");
            Console.WriteLine();
        }

        static IEnumerable<int> Fibonacci(int count)
        {
            int prev = 0, curr = 1;
            for (int i = 0; i < count; i++)
            {
                yield return prev;
                (prev, curr) = (curr, prev + curr);
            }
        }
    }
}

