namespace CSharpAsyncAwait
{
    public class AsyncService
    {
        private readonly HttpClient _httpClient = new HttpClient();

        public async Task<string> FetchDataAsync(string url)
        {
            return await _httpClient.GetStringAsync(url);
        }

        public async Task<string> FetchWithCancel(string url, CancellationToken ct)
        {
            var response = await _httpClient.GetAsync(url, ct);
            return await response.Content.ReadAsStringAsync(ct);
        }

        public async Task<List<string>> FetchAllAsync(string[] urls)
        {
            var tasks = urls.Select(url => _httpClient.GetStringAsync(url));
            string[] results = await Task.WhenAll(tasks);
            return new List<string>(results);
        }
    }

    class Program
    {
        static async Task Main(string[] args)
        {
            var service = new AsyncService();

            var task1 = Task.Delay(50);
            var task2 = Task.Delay(50);
            await Task.WhenAll(task1, task2);
            Console.WriteLine("Hoàn thành sau ~50ms");

            using var cts = new CancellationTokenSource();
            cts.CancelAfter(100);
            try
            {
                await Task.Delay(500, cts.Token);
            }
            catch (TaskCanceledException)
            {
                Console.WriteLine("Operation bị hủy!");
            }

            try
            {
                await ThrowAsync();
            }
            catch (InvalidOperationException ex)
            {
                Console.WriteLine($"Bắt được: {ex.Message}");
            }
        }

        static async Task ThrowAsync()
        {
            await Task.Delay(10);
            throw new InvalidOperationException("Lỗi xảy ra!");
        }
    }
}

