namespace RoutingControllersActionResults
{
    public class CreateProductRequest
    {
        [Required(ErrorMessage = "Tên bắt buộc")]
        [StringLength(100, MinimumLength = 2)]
        public string Name { get; set; }

        [Range(0.01, 1000000)]
        public decimal Price { get; set; }

        [FromQuery(Name = "category_id")]
        public int? CategoryId { get; set; }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class ProductsController : ControllerBase
    {
        private static readonly List<object> _products = new();

        [HttpGet]
        public ActionResult GetAll([FromQuery] int page = 1, [FromQuery] int pageSize = 10)
        {
            return Ok(new { products = _products, page, pageSize });
        }

        [HttpGet("{id:int}")]
        public ActionResult GetById(int id)
        {
            if (id <= 0) return BadRequest(new { error = "ID không hợp lệ" });
            return Ok(new { id, name = "Product " + id });
        }

        [HttpPost]
        public ActionResult Create([FromBody] CreateProductRequest request)
        {
            if (!ModelState.IsValid)
                return UnprocessableEntity(ModelState);

            var newProduct = new { id = _products.Count + 1, request.Name, request.Price };
            _products.Add(newProduct);
            return CreatedAtAction(nameof(GetById), new { id = newProduct.id }, newProduct);
        }

        [HttpDelete("{id:int}")]
        public ActionResult Delete(int id)
        {
            return NoContent();
        }
    }

    class Program
    {
        static void Main()
        {
            Console.WriteLine("=== ROUTING, CONTROLLERS & ACTION RESULTS ===");
            Console.WriteLine("GET    api/products                    — List all");
            Console.WriteLine("GET    api/products/{id:int}          — Get by ID");
            Console.WriteLine("POST   api/products                   — Create");
            Console.WriteLine("DELETE api/products/{id}             — Delete");
        }
    }
