namespace MiddlewareFiltersPipeline
{
    public class RateLimitingMiddleware
    {
        private readonly RequestDelegate _next;
        private int _requestCount = 0;

        public RateLimitingMiddleware(RequestDelegate next) => _next = next;

        public async Task InvokeAsync(HttpContext context)
        {
            if (++_requestCount > 100)
            {
                context.Response.StatusCode = 429;
                await context.Response.WriteAsJsonAsync(new { error = "Too Many Requests" });
                return;
            }
            await _next(context);
        }
    }

    public class TimingActionFilter : IAsyncActionFilter
    {
        public async Task OnActionExecutionAsync(ActionExecutingContext context, ActionExecutionDelegate next)
        {
            var sw = System.Diagnostics.Stopwatch.StartNew();
            Console.WriteLine($"Action started: {context.ActionDescriptor.DisplayName}");
            var result = await next();
            sw.Stop();
            Console.WriteLine($"Action completed in {sw.ElapsedMilliseconds}ms");
        }
    }

    public class GlobalExceptionFilter : IExceptionFilter
    {
        public void OnException(ExceptionContext context)
        {
            context.Result = new ObjectResult(new
            {
                code = "INTERNAL_ERROR",
                message = context.Exception.Message
            }) { StatusCode = 500 };
        }
    }

    public class Configure
    {
        public static void ConfigureMiddleware(WebApplication app)
        {
            app.UseExceptionHandler("/error");
            app.UseCorrelationId();
            app.UseRateLimiting();
            app.UseRouting();
            app.MapControllers();
        }
    }

    class Program
    {
        static void Main()
        {
            Console.WriteLine("Middleware Pipeline Order:");
            Console.WriteLine("  1. ExceptionHandler");
            Console.WriteLine("  2. StaticFiles");
            Console.WriteLine("  3. CorrelationId");
            Console.WriteLine("  4. RateLimiting");
            Console.WriteLine("  5. Authentication");
            Console.WriteLine("  6. CORS");
            Console.WriteLine("  7. Routing");
            Console.WriteLine("  8. MapControllers");
        }
    }
}

using System;
using Microsoft.Extensions.DependencyInjection;

namespace DependencyInjectionLifetimes
{
    public interface IProductService { int GetInstanceId(); }

    public class SingletonService : IProductService
    {
        private readonly int _instanceId = new Random().Next(1000, 9999);
        public int GetInstanceId() => _instanceId;
        public SingletonService() => Console.WriteLine($"[Singleton] Instance: {_instanceId}");
    }

    public class ScopedService : IProductService
    {
        private readonly int _instanceId = new Random().Next(1000, 9999);
        public int GetInstanceId() => _instanceId;
        public ScopedService() => Console.WriteLine($"[Scoped] Instance: {_instanceId}");
    }

    public class TransientService : IProductService
    {
        private readonly int _instanceId = new Random().Next(1000, 9999);
        public int GetInstanceId() => _instanceId;
        public TransientService() => Console.WriteLine($"[Transient] Instance: {_instanceId}");
    }

    class Program
    {
        static void Main()
        {
            var services = new ServiceCollection();
            services.AddSingleton<IProductService, SingletonService>();
            services.AddScoped<IProductService, ScopedService>();
            services.AddTransient<IProductService, TransientService>();

            var provider = services.BuildServiceProvider();

            Console.WriteLine("\n--- REQUEST 1 ---");
            using (var scope = provider.CreateScope())
            {
                var s1 = scope.ServiceProvider.GetRequiredService<IProductService>();
                var s2 = scope.ServiceProvider.GetRequiredService<IProductService>();
                Console.WriteLine($"Singleton same? {s1.GetInstanceId() == s2.GetInstanceId()}");
            }

            Console.WriteLine("\n--- REQUEST 2 ---");
            using (var scope = provider.CreateScope())
            {
                var s = scope.ServiceProvider.GetRequiredService<IProductService>();
                Console.WriteLine($"Scoped ID: {s.GetInstanceId()}");
            }

            Console.WriteLine("\n⚠️ Captive Dependency:");
            Console.WriteLine("  WRONG: AddSingleton<ScopedService>()");
            Console.WriteLine("  RIGHT: AddScoped<ScopedService>()");
        }
    }
}

using System;
using System.Collections.Generic;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.IdentityModel.Tokens;

namespace JWTAuthenticationAuthorization
{
    public class JwtService
    {
        private readonly string _secretKey = "YourSuperSecretKeyThatIsAtLeast32CharactersLong!";

        public string GenerateToken(string userId, string username, List<string> roles)
        {
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_secretKey));
            var credentials = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var claims = new List<Claim>
            {
                new(JwtRegisteredClaimNames.Sub, userId),
                new("username", username)
            };
            foreach (var role in roles)
                claims.Add(new Claim(ClaimTypes.Role, role));

            var token = new JwtSecurityToken(
                issuer: "MyApp",
                audience: "MyAppUsers",
                claims: claims,
                expires: DateTime.UtcNow.AddMinutes(15),
                signingCredentials: credentials);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }

        public ClaimsPrincipal? ValidateToken(string token)
        {
            var tokenHandler = new JwtSecurityTokenHandler();
            var key = Encoding.UTF8.GetBytes(_secretKey);
            try
            {
                return tokenHandler.ValidateToken(token, new TokenValidationParameters
                {
                    ValidateIssuerSigningKey = true,
                    IssuerSigningKey = new SymmetricSecurityKey(key),
                    ValidateIssuer = true,
                    ValidIssuer = "MyApp",
                    ValidateAudience = true,
                    ValidAudience = "MyAppUsers",
                    ValidateLifetime = true
                }, out _);
            }
            catch { return null; }
        }
    }

    class Program
    {
        static void Main()
        {
            var jwtService = new JwtService();
            var token = jwtService.GenerateToken("1", "admin", new List<string> { "Admin", "User" });
            Console.WriteLine($"JWT: {token[..50]}...");

            var principal = jwtService.ValidateToken(token);
            Console.WriteLine($"User: {principal?.FindFirst("username")?.Value}");
            Console.WriteLine($"Roles: {string.Join(", ", principal?.Claims.Where(c => c.Type == ClaimTypes.Role).Select(c => c.Value))}");
        }
    }
}

