namespace CQRSMediatR
{
    // CQRS — SEPARATE MODELS FOR READ AND WRITE
    public record CreateProductCommand(string Name, decimal Price, int Stock);
    public record ProductListDto(int Id, string Name, decimal Price, bool InStock);
    public record ProductDetailDto(int Id, string Name, decimal Price, int Stock, List<string> Reviews);

    // MEDIATR — REQUEST & HANDLER INTERFACES
    public interface IRequest<TResponse> { }
    public interface IRequestHandler<TRequest, TResponse> where TRequest : IRequest<TResponse>
    {
        Task<TResponse> Handle(TRequest request, CancellationToken ct);
    }

    // COMMAND HANDLER
    public class CreateProductHandler : IRequestHandler<CreateProductCommand, int>
    {
        public Task<int> Handle(CreateProductCommand request, CancellationToken ct)
        {
            var newId = new Random().Next(1, 10000);
            Console.WriteLine($"[Command] Created: {request.Name} (ID: {newId})");
            return Task.FromResult(newId);
        }
    }

    // QUERY HANDLER
    public record GetProductsQuery(int Page, int PageSize) : IRequest<List<ProductListDto>>;

    public class GetProductsHandler : IRequestHandler<GetProductsQuery, List<ProductListDto>>
    {
        public Task<List<ProductListDto>> Handle(GetProductsQuery request, CancellationToken ct)
        {
            var products = Enumerable.Range(1, 50).Select(i => new ProductListDto(i, $"Product {i}", i * 10.99m, i % 3 != 0)).ToList();
            Console.WriteLine($"[Query] Returning {products.Count} products");
            return Task.FromResult(products);
        }
    }

    // PIPELINE BEHAVIOR
    public interface IPipelineBehavior<TRequest, TResponse>
    {
        Task<TResponse> Handle(TRequest request, CancellationToken ct, RequestHandlerDelegate<TResponse> next);
    }
    public delegate Task<TResponse> RequestHandlerDelegate<TResponse>();

    public class LoggingBehavior<TRequest, TResponse> : IPipelineBehavior<TRequest, TResponse>
    {
        public async Task<TResponse> Handle(TRequest request, CancellationToken ct, RequestHandlerDelegate<TResponse> next)
        {
            Console.WriteLine($"[CQRS] Handling {typeof(TRequest).Name}");
            var result = await next();
            Console.WriteLine($"[CQRS] Completed {typeof(TRequest).Name}");
            return result;
        }
    }

    class Program
    {
        static async Task Main()
        {
            Console.WriteLine("Commands (Write): CreateProductCommand, UpdateProductCommand");
            Console.WriteLine("Queries (Read): GetProductsQuery, GetProductByIdQuery");
            Console.WriteLine("Pipeline Behaviors: Validation, Logging, Performance");

            var handler = new CreateProductHandler();
            var id = await handler.Handle(new CreateProductCommand("Laptop", 20000000, 10), CancellationToken.None);
            Console.WriteLine($"Created Product ID: {id}");
        }
    }
}

