namespace CachingAndBackgroundJobs
{
    public class InMemoryCacheService
    {
        private readonly IMemoryCache _cache;
        private static readonly TimeSpan DefaultExpiration = TimeSpan.FromMinutes(10);

        public InMemoryCacheService(IMemoryCache cache) => _cache = cache;

        public T? GetOrSet<T>(string key, Func<T?> factory)
        {
            if (_cache.TryGetValue(key, out T? value))
            {
                Console.WriteLine($"[Cache] HIT: {key}");
                return value;
            }
            Console.WriteLine($"[Cache] MISS: {key}");
            value = factory();
            if (value != null)
                _cache.Set(key, value, DefaultExpiration);
            return value;
        }

        public void Remove(string key) => _cache.Remove(key);
    }

    public class RedisCacheService
    {
        public async Task<T?> GetAsync<T>(string key)
        {
            Console.WriteLine($"[Redis] GET: {key}");
            return default;
        }

        public async Task SetAsync<T>(string key, T value, TimeSpan? expiration = null)
        {
            Console.WriteLine($"[Redis] SET: {key} (expires: {expiration?.TotalMinutes ?? 15} min)");
        }

        public async Task<List<Product>> GetProductsAsync(int categoryId)
        {
            var cacheKey = $"products:category:{categoryId}";
            var cached = await GetAsync<List<Product>>(cacheKey);
            if (cached != null) return cached;

            var products = await LoadProductsFromDb(categoryId);
            await SetAsync(cacheKey, products, TimeSpan.FromMinutes(10));
            return products;
        }

        private Task<List<Product>> LoadProductsFromDb(int categoryId)
        {
            Console.WriteLine($"[DB] Loading products for category {categoryId}");
            return Task.FromResult(new List<Product>());
        }
    }

    public class Product { public int Id { get; set; } public string Name { get; set; } }

    class Program
    {
        static async Task Main()
        {
            var cache = new InMemoryCacheService(new MemoryCache(new MemoryCacheOptions()));
            var result = cache.GetOrSet("test-key", () => "expensive-result");
            Console.WriteLine($"Result: {result}");

            var redis = new RedisCacheService();
            await redis.GetProductsAsync(1);
        }
    }
}

