        {
            _containerName = containerName;
        }

        public string GenerateUploadUrl(string blobName, string contentType, int expiryMinutes = 15)
        {
            var sasToken = $"?sv=2021-06-08&ss=b&srt=co&sp=wd&se=2024-12-31T23:59:59Z&st=2024-01-01T00:00:00Z&spr=https&sig=...";
            var url = $"https://storage.blob.core.windows.net/{_containerName}/{blobName}{sasToken}";
