            return url;
        }

        public string GenerateDownloadUrl(string blobName, int expiryMinutes = 60)
        {
            Console.WriteLine($"[Azure] Generated download URL for: {blobName}");
            return $"https://storage.blob.core.windows.net/{_containerName}/{blobName}?...";
        }
    }

    public class FileUploadController
    {
        private readonly AzureBlobService _blobService;

        public record PresignRequest(string FileName, string ContentType, long FileSize);
        public record PresignResponse(string UploadUrl, string BlobName, string FinalUrl);

        public PresignResponse GeneratePresignedUrl(PresignRequest request, int userId)
        {
            var allowedTypes = new[] { "image/jpeg", "image/png", "image/webp", "application/pdf" };
            if (!allowedTypes.Contains(request.ContentType))
                throw new InvalidOperationException($"Content type {request.ContentType} not allowed");

            var maxSize = 10L * 1024 * 1024;
            if (request.FileSize > maxSize)
                throw new InvalidOperationException("File size exceeds limit");

            var extension = Path.GetExtension(request.FileName);
            var blobName = $"uploads/{userId}/{Guid.NewGuid():N}{extension}";
            var uploadUrl = _blobService.GenerateUploadUrl(blobName, request.ContentType, 15);
            var downloadUrl = _blobService.GenerateDownloadUrl(blobName, 60);

            return new PresignResponse(uploadUrl, blobName, downloadUrl);
        }
    }

    class Program
    {
        static void Main()
        {
            var blobService = new AzureBlobService("uploads");
            var presignedUrl = blobService.GenerateUploadUrl("avatar.jpg", "image/jpeg", 15);
            Console.WriteLine($"Presigned URL: {presignedUrl[..60]}...");
        }
    }
}

