namespace SignalRRealtime
{
    public class ChatHub : Hub
    {
        private static readonly ConcurrentDictionary<string, string> _userConnections = new();

        public async Task JoinRoom(string roomId, string username)
        {
            await Groups.AddToGroupAsync(Context.ConnectionId, roomId);
            _userConnections[Context.ConnectionId] = username;

            await Clients.Group(roomId).SendAsync("UserJoined", new
            {
                Username = username,
                JoinedAt = DateTime.UtcNow
            });

            Console.WriteLine($"[Chat] {username} joined room {roomId}");
        }

        public async Task SendMessage(string roomId, string message)
        {
            var username = _userConnections.GetValueOrDefault(Context.ConnectionId, "Anonymous");
            await Clients.Group(roomId).SendAsync("ReceiveMessage", new
            {
                Username = username,
                Content = message,
                SentAt = DateTime.UtcNow
            });

            Console.WriteLine($"[Chat] {username}: {message}");
        }

        public async Task LeaveRoom(string roomId)
        {
            await Groups.RemoveFromGroupAsync(Context.ConnectionId, roomId);
            var username = _userConnections.GetValueOrDefault(Context.ConnectionId, "");
            await Clients.Group(roomId).SendAsync("UserLeft", new { Username = username });
        }

        public override async Task OnDisconnectedAsync(Exception? exception)
        {
            if (_userConnections.TryRemove(Context.ConnectionId, out var username))
                Console.WriteLine($"[SignalR] {username} disconnected");
            await base.OnDisconnectedAsync(exception);
        }
    }

