            Console.WriteLine("  clients.Group(name).SendAsync() — Broadcast to group");
            Console.WriteLine("  clients.User(id).SendAsync() — Send to all user's connections");
            Console.WriteLine("  clients.Client(id).SendAsync() — Send to specific connection");
            Console.WriteLine();
            Console.WriteLine("Groups: Groups.AddToGroupAsync(), Groups.RemoveFromGroupAsync()");
            Console.WriteLine("Scale: Redis Backplane — share messages across server instances");
        }
    }
