namespace GameServerArchitecture
{
    public class GameServer
    {
        private const int TickRate = 20; // 20 ticks per second
        private readonly ConcurrentDictionary<string, GameRoom> _rooms = new();
        private CancellationTokenSource _cts = new();

        public GameServer() => StartGameLoop();

        private async Task StartGameLoop()
        {
            Console.WriteLine($"[Server] Starting game loop at {TickRate} ticks/second");
            var tickIntervalMs = 1000 / TickRate;

            while (!_cts.Token.IsCancellationRequested)
            {
                var tickStart = DateTime.UtcNow;
                ProcessPendingMessages();
                UpdateGameState();
                BroadcastState();
                var elapsed = (DateTime.UtcNow - tickStart).TotalMilliseconds;
                if (tickIntervalMs - elapsed > 0)
                    await Task.Delay((int)(tickIntervalMs - elapsed));
            }
        }

        private ConcurrentQueue<object> _messageQueue = new();

        private void ProcessPendingMessages()
        {
            while (_messageQueue.TryDequeue(out var message))
            {
                // Process game messages
            }
        }

        private void UpdateGameState()
        {
            foreach (var room in _rooms.Values)
            {
                if (room.State != RoomState.Playing) continue;
                room.UpdatePhysics(1.0f / TickRate);
                room.CheckCollisions();
            }
        }

        private void BroadcastState()
        {
            foreach (var room in _rooms.Values)
            {
                if (room.State != RoomState.Playing) continue;
                var delta = room.GetStateDelta();
                foreach (var playerId in room.PlayerIds)
                    SendToPlayer(playerId, delta);
            }
        }

        private void SendToPlayer(string connectionId, object state) { }

        public class GameRoom
        {
            public string Id { get; set; }
            public RoomState State { get; set; } = RoomState.Lobby;
            public List<string> PlayerIds { get; set; } = new();
            public ConcurrentDictionary<string, GameEntity> Entities { get; set; } = new();

            public void UpdatePhysics(float deltaTime)
            {
                foreach (var entity in Entities.Values)
                    entity.Update(deltaTime);
            }

            public void CheckCollisions() { }
            public object GetStateDelta() => new { };
        }

        public class GameEntity
        {
            public string Id { get; set; }
            public float X, Y, Z;
            public void Update(float deltaTime) { X += deltaTime; }
        }

        public enum RoomState { Lobby, Playing, Ended }
    }

    class Program
    {
        static void Main()
        {
            Console.WriteLine("Stateful vs Stateless:");
            Console.WriteLine("  Stateful: Server lưu game state (FPS, MMO)");
            Console.WriteLine("  Stateless: Client authoritative (Puzzle, Card games)");
            Console.WriteLine();
            Console.WriteLine("Tick Rate: 20-64 ticks/sec typical");

            var server = new GameServer();
            Thread.Sleep(500);
        }
    }
}

