    }

    public class EloRatingService
    {
        private const int DefaultRating = 1000;
        private const int KFactor = 32;

        public (int NewWinnerRating, int NewLoserRating) CalculateMatch(int winnerRating, int loserRating)
        {
            double Ew = 1.0 / (1.0 + Math.Pow(10, (loserRating - winnerRating) / 400.0));
            double El = 1.0 / (1.0 + Math.Pow(10, (winnerRating - loserRating) / 400.0));

            int newWinnerRating = (int)(winnerRating + KFactor * (1 - Ew));
            int newLoserRating = (int)(loserRating + KFactor * (0 - El));

            return (newWinnerRating, newLoserRating);
        }
    }

