    {
        static async Task Main()
        {
            var leaderboard = new RedisLeaderboardService();
            await leaderboard.UpdateScoreAsync("Player1", 1500);
            var rank = await leaderboard.GetRankAsync("Player1");
            Console.WriteLine($"Rank: {rank}");

            var top = await leaderboard.GetTopPlayersAsync(5);
            foreach (var entry in top)
                Console.WriteLine($"#{entry.Rank} {entry.Username}: {entry.Score}");

            var elo = new EloRatingService();
            var (winnerNew, loserNew) = elo.CalculateMatch(1200, 1100);
